import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'

/* The handleChange function is assumed to be exported from './module' */
import { handleChange } from './module'

describe('handleChange', () => {
  // Helper mock event
  const createEvent = (value: any) => ({
    target: { value }
  })

  it('should handle happy path - return the event target value when a string is provided', () => {
    const event = createEvent('test value')
    const result = handleChange(event as any)
    expect(result).toBe('test value')
  })

  it('should handle edge case - return the event target value when a number is provided', () => {
    const event = createEvent(42)
    const result = handleChange(event as any)
    expect(result).toBe(42)
  })

  it('should handle null/empty - return undefined when event or event.target.value is null or undefined', () => {
    // null event
    const resultNull = handleChange(null as any)
    expect(resultNull).toBeUndefined()

    // event with undefined value
    const resultUndefined = handleChange({ target: { value: undefined } } as any)
    expect(resultUndefined).toBeUndefined()

    // event with empty string
    const resultEmpty = handleChange({ target: { value: '' } } as any)
    expect(resultEmpty).toBe('')
  })
})

